import pytest
# Assuming the function is saved in a module named palindrome.py
from palindrome import is_palindrome


class TestIsPalindrome:
    """Unit tests for the is_palindrome function."""

    # ---------- Happy Path ----------
    def test_simple_palindrome(self):
        assert is_palindrome("racecar") is True

    def test_case_insensitive_palindrome(self):
        assert is_palindrome("RaceCar") is True

    def test_palindrome_with_spaces(self):
        assert is_palindrome("A man a plan a canal Panama") is True

    def test_palindromic_numbers_as_string(self):
        assert is_palindrome("12321") is True

    # ---------- Edge Cases ----------
    def test_empty_string(self):
        assert is_palindrome("") is True

    def test_single_character(self):
        assert is_palindrome("a") is True
        assert is_palindrome("Z") is True

    def test_only_spaces(self):
        assert is_palindrome("   ") is True  # spaces removed -> empty string

    def test_palindrome_with_leading_trailing_spaces(self):
        assert is_palindrome("  never odd or even  ") is True

    def test_non_palindrome(self):
        assert is_palindrome("hello") is False

    def test_non_palindrome_with_spaces(self):
        assert is_palindrome("hello world") is False

    def test_string_with_punctuation(self):
        # The function only removes spaces, not punctuation.
        # "No 'x' in Nixon" after lowering and space removal becomes "no'x'innixon"
        # which is not a palindrome.
        assert is_palindrome("No 'x' in Nixon") is False

    def test_palindrome_with_punctuation_if_symmetric(self):
        # If the punctuation is symmetric, it can still be a palindrome.
        assert is_palindrome("a!a") is True

    # ---------- Error / Invalid Input ----------
    def test_none_input_raises_error(self):
        with pytest.raises(AttributeError):
            is_palindrome(None)

    def test_integer_input_raises_error(self):
        with pytest.raises(AttributeError):
            is_palindrome(123)

    def test_list_input_raises_error(self):
        with pytest.raises(AttributeError):
            is_palindrome(["a", "b", "a"])
